export function nextGeneration(cells: Cell[]): Cell[] {
  const live = new Set(cells.map(cellKey));
  const candidates = new Map<string, { cell: Cell; count: number }>();

  for (const cell of cells) {
    for (const neighbor of neighborsOf(cell)) {
      const k = cellKey(neighbor);
      const entry = candidates.get(k);
      if (entry) entry.count += 1;
      else candidates.set(k, { cell: neighbor, count: 1 });
    }
  }

  const result: Cell[] = [];
  for (const [k, { cell, count }] of candidates) {
    if (survives(count, live.has(k))) result.push(cell);
  }
  return result;
}

